import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Video } from 'lucide-react';

export default function DiscoverPage() {
  const { token, API_URL } = useAuth();
  const [users, setUsers] = useState([]);
  const [filter, setFilter] = useState('any');
  const [loading, setLoading] = useState(true);

  const fetchUsers = async () => {
    try {
      const res = await fetch(`${API_URL}/api/users`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setUsers(data);
    } catch (err) {
      console.error('Failed to fetch users:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchUsers(); }, []);
  // eslint-disable-next-line react-hooks/exhaustive-deps

  const filtered = filter === 'any' ? users : users.filter(u => u.gender === filter);
  const online = filtered.filter(u => u.online);
  const display = online.length > 0 ? online : filtered;

  const handleLike = async (userId) => {
    const res = await fetch(`${API_URL}/api/match`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
      body: JSON.stringify({ userId }),
    });
    if (res.ok) {
      fetchUsers();
    }
  };

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div>
      <div className="discover-header">
        <h1>Discover People</h1>
        <p>Find someone to talk to — swipe right to match</p>
      </div>

      <div className="filter-bar">
        <button className={`filter-btn ${filter === 'any' ? 'active' : ''}`} onClick={() => setFilter('any')}>Everyone</button>
        <button className={`filter-btn ${filter === 'female' ? 'active' : ''}`} onClick={() => setFilter('female')}>Women</button>
        <button className={`filter-btn ${filter === 'male' ? 'active' : ''}`} onClick={() => setFilter('male')}>Men</button>
        <Link to="/video" className="filter-btn" style={{ marginLeft: 'auto', background: 'var(--primary)', color: '#fff', display: 'flex', alignItems: 'center', gap: 6 }}>
          <Video size={14} /> Video Chat
        </Link>
      </div>

      <div className="users-grid">
        {display.length === 0 ? (
          <p style={{ gridColumn: '1/-1', textAlign: 'center', color: 'var(--text-muted)', padding: '40px 0' }}>
            No users found. Check back later or try different filters.
          </p>
        ) : (
          display.map(user => (
            <div key={user.id} className="user-card">
              <div className="user-card-avatar">
                {user.avatarUrl ? (
                  <img src={user.avatarUrl} alt={user.name} />
                ) : (
                  user.name?.charAt(0).toUpperCase() || '?'
                )}
                {user.online && <span className="online-dot" />}
              </div>
              <div className="user-card-info">
                <h3>{user.name || user.username}{user.age ? `, ${user.age}` : ''}</h3>
                <p className="meta">{user.gender}{user.online ? ' — Online' : ' — Offline'}</p>
                <p className="bio">{user.bio || 'No bio yet'}</p>
              </div>
              <div className="match-action">
                <button className="match-btn like" onClick={() => handleLike(user.id)}>Match</button>
                <Link to="/chat" className="match-btn skip">Message</Link>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
